                WriteLiteral(@"
    <script>
        // دالة الصورة الأساسية
        function updateFileName(input) {
            var display = document.getElementById('fileNameDisplay');
            var zone = document.getElementById('dropZone');
            if (input.files && input.files.length > 0) {
                display.innerText = ""Selected: "" + input.files[0].name;
                display.style.display = ""inline-block"";
                zone.classList.add('file-selected');
            }
        }

        // دالة الألبوم
        function updateGalleryCount(input) {
            var display = document.getElementById('galleryCountDisplay');
            var zone = document.getElementById('galleryZone');
            var count = input.files.length;
            if (count > 0) {
                display.innerText = count + "" images selected for gallery"";
                display.style.display = ""inline-block"";
                zone.style.borderColor = ""#2ecc71"";
            } else {
                display.innerText = """);
                WriteLiteral(@"No images selected"";
                display.style.display = ""none"";
                zone.style.borderColor = ""#3498db"";
            }
        }

        // تحويل الزرار لـ Loading وقت الرفع لضمان عدم الخروج من الصفحة
        document.getElementById('createForm').onsubmit = function () {
            if ($(this).valid()) {
                var btn = document.getElementById('submitBtn');
                btn.classList.add('disabled');
                btn.style.opacity = ""0.7"";
                btn.querySelector('.btn-text').style.display = 'none';
                btn.querySelector('.btn-loading').style.display = 'inline-block';
            }
        };
    </script>
");
            }
